// ─── Helpers (same as before) ───────────────
function createPokemonInstance(key, level = 50, opts = {}) {
  const template = POKEMON_DATA[key];
  if (!template) { console.error('No Pokémon:', key); return null; }
  const bs = template.baseStats;
  const calcStat = b => Math.floor(((2 * b * level) / 100) + 5);
  const maxHP    = Math.floor(((2 * bs.hp * level) / 100) + level + 10);
  const moves = template.moves.map(id => {
    const m = MOVES_DATA[id];
    if (!m) return null;
    return { ...m, id, currentPP: m.pp };
  }).filter(Boolean);
  if (moves.length === 0) {
    const fallback = MOVES_DATA['tackle'];
    if (fallback) moves.push({ ...fallback, id: 'tackle', currentPP: fallback.pp });
  }
  return {
    key, id: template.id, name: template.name, types: [...template.types],
    level, maxHP, currentHP: maxHP,
    stats: { attack: calcStat(bs.attack), defense: calcStat(bs.defense),
             spatk: calcStat(bs.spatk),   spdef: calcStat(bs.spdef), speed: calcStat(bs.speed) },
    moves, status: null,
    stages: { attack:0, defense:0, spatk:0, spdef:0, speed:0 },
    isShiny:       opts?.shiny || false,
    spriteUrl:     getSpriteUrl(template.id,     opts?.shiny || false),
    backSpriteUrl: getBackSpriteUrl(template.id, opts?.shiny || false),
  };
}

function getUnlockedPokemon() {
  return Object.keys(POKEMON_DATA).filter(k => POKEMON_DATA[k].unlocked);
}

function unlockPokemon(key) {
  if (POKEMON_DATA[key]) POKEMON_DATA[key].unlocked = true;
}